module top_module(
    input [15:0] a,
    input [15:0] b,
    input [1:0] op, // Select between addition, subtraction, and bitwise AND
    output reg [31:0] result // Changed to reg since we're assigning in an always block
);wire [15:0] adder_out;
wire [15:0] sub_out;
wire [15:0] and_out;

  wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign adder_out = {_n01, _n02, _n03, _n04};
assign sub_out = a - b;
assign and_out = a & b;

always @(*) begin
    case (op)
        2'b00: result = {16'b0, adder_out}; // Addition
        2'b01: result = {16'b0, sub_out};   // Subtraction
        2'b10: result = {16'b0, and_out};   // Bitwise AND
        default: result = 32'b0;            // Default to zero if invalid op
    endcase
end

endmodule
